mapper.select:
SELECT * FROM haosen_project..md_fuzzy_match_batch


        AND batch_id = #{batchId}


        AND status = #{status}


        AND data_type = #{dataType}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY create_time DESC

SELECT a.id, a.original_province, a.original_name, a.original_address, a.keyid, a.remark, a.batch_id, a.data_type, a.create_time, a.update_time,
       b.name, b.namehistory, b.province, b.cityname, b.areaname, b.address, b.legalperson, b.principal, b.sign_status, b.qcc_status
FROM haosen_project..md_fuzzy_match_summary a
LEFT JOIN (
    SELECT keyid, name, namehistory, province, cityname, areaname, address, legalperson, principal, null sign_status, status qcc_status
    FROM HospitalInfo..hospital
    UNION ALL
    SELECT key_id, name, history_name, province, city_name, area_name, address, oper_name, null principal, qcc_status sign_status, status
    FROM HospitalInfo..company
) b ON a.keyid = b.keyid


        AND a.batch_id = #{batchId}


        AND a.data_type = #{dataType}


        AND a.id = #{originalId}


        AND a.original_province = #{originalProvince}


        AND a.original_name LIKE CONCAT('%', #{originalName}, '%')


        AND a.original_address LIKE CONCAT('%', #{originalAddress}, '%')


        AND a.keyid = #{keyid}


        AND b.name LIKE CONCAT('%', #{name}, '%')


ORDER BY a.create_time DESC

SELECT TOP 2 keyid, name
FROM HospitalInfo..hospital
WHERE status = 1

    AND province = #{province}

AND name LIKE #{namePattern}

SELECT TOP 2 keyid, name FROM HospitalInfo..hospital WHERE status = 1
AND province = #{province}
AND (name LIKE #{namePattern} OR namehistory LIKE #{namePattern})

SELECT TOP 2 key_id keyid, name FROM HospitalInfo..company WHERE status = 1
AND province = #{province}
AND (name LIKE #{namePattern} OR history_name LIKE #{namePattern})

SELECT TOP 2 key_id keyid, name
FROM HospitalInfo..company
WHERE status = 1

    AND province = #{province}

AND name LIKE #{namePattern}
